module counter_3bit(
    input clk,
    input rst,
    output reg [2:0] count
    );

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @ (posedge clk or posedge dbg_halt)
    begin
        if (rst)
            count = 3'b000;
        else
            count = count + 1;
    end
endmodule
